/**
 * Nxcode SDK
 *
 * A lightweight SDK for integrating Nxcode authentication, billing,
 * and payment features into web applications.
 *
 * Usage:
 *   <script src="https://sdk.nxcode.io/v1/nxcode.js"></script>
 *   <script>
 *     const user = await Nxcode.auth.login();
 *     console.log('Logged in:', user.email);
 *   </script>
 */

import { NxcodeAuth } from './auth';
import { NxcodeBilling } from './billing';
import { NxcodePayment } from './payment';
import { NxcodeAI, type ChatOptions, type ChatResponse, type GenerateOptions, type GenerateResponse, type StreamChunk, type StreamCallback, type ChatMessage, type ContentPart, type TextPart, type ImagePart, type ImageUrlPart, type SimpleSchema } from './ai';
import { Agent, type AgentTool, type AgentOptions, type AgentRunCallbacks, type AgentResult } from './agent';
import type {
  NxcodeUser,
  NxcodeConfig,
  ChargeOptions,
  ChargeResult,
  Transaction,
  AuthStateCallback,
} from './types';

// API endpoint - auto-detect or use default
const DEFAULT_API_ENDPOINT = 'https://studio-api.nxcode.io';

class NxcodeSDK {
  private config: NxcodeConfig | null = null;
  private _auth: NxcodeAuth | null = null;
  private _billing: NxcodeBilling | null = null;
  private _payment: NxcodePayment | null = null;
  private _ai: NxcodeAI | null = null;
  private initPromise: Promise<void> | null = null;
  private apiEndpoint: string;

  constructor() {
    this.apiEndpoint = this.detectApiEndpoint();
    this.autoInit();
  }

  /**
   * Auto-initialize SDK based on environment
   */
  private async autoInit(): Promise<void> {
    if (this.initPromise) return this.initPromise;

    this.initPromise = this.init();
    return this.initPromise;
  }

  /**
   * Initialize SDK by fetching configuration
   */
  private async init(): Promise<void> {
    try {
      // Try to get config from server
      const response = await fetch(`${this.apiEndpoint}/api/sdk/config`, {
        credentials: 'include',
      });

      if (response.ok) {
        this.config = await response.json();
        this.config!.apiEndpoint = this.apiEndpoint;
        this.setupModules();
      }
    } catch (error) {
      console.warn('Nxcode SDK: Could not auto-detect app config. Call Nxcode.configure() manually.');
    }
  }

  /**
   * Manually configure SDK with app ID and optional endpoint
   */
  configure(appId: string, options?: { apiEndpoint?: string }): void {
    if (options?.apiEndpoint) {
      this.apiEndpoint = options.apiEndpoint;
    }
    this.config = {
      appId,
      name: '',
      billingMode: 'creator_pays',
      apiEndpoint: this.apiEndpoint,
    };
    this.setupModules();
  }

  /**
   * Set up SDK modules after configuration
   */
  private setupModules(): void {
    if (!this.config) return;

    this._auth = new NxcodeAuth(this.config.apiEndpoint, this.config.appId);
    this._billing = new NxcodeBilling(
      this.config.apiEndpoint,
      this.config.appId,
      () => this._auth?.getToken() || null
    );
    this._payment = new NxcodePayment(
      this.config.apiEndpoint,
      this.config.appId,
      () => this._auth?.getToken() || null
    );
    this._ai = new NxcodeAI(
      this.config.apiEndpoint,
      this.config.appId,
      () => this._auth?.getToken() || null
    );
  }

  /**
   * Detect API endpoint based on environment
   */
  private detectApiEndpoint(): string {
    if (typeof window !== 'undefined') {
      const hostname = window.location.hostname;

      // Development environment
      if (hostname === 'localhost' || hostname === '127.0.0.1') {
        return 'http://localhost:8001';
      }

      // Check for dev environment
      if (hostname.includes('.nxcode.dev') || hostname.includes('.nxcode.app')) {
        return 'https://studio-api.nxcode.io';
      }
    }

    return DEFAULT_API_ENDPOINT;
  }

  /**
   * Ensure SDK is initialized before operations
   */
  private async ensureInitialized(): Promise<void> {
    if (this.initPromise) {
      await this.initPromise;
    }

    if (!this.config) {
      throw new Error(
        'Nxcode SDK not configured. Add X-App-Id header or call Nxcode.configure(appId).'
      );
    }
  }

  // ==================== Auth Module ====================

  get auth() {
    const self = this;

    return {
      /**
       * Login via OAuth popup
       */
      async login(provider: 'google' | 'github' = 'google'): Promise<NxcodeUser> {
        await self.ensureInitialized();
        return self._auth!.login(provider);
      },

      /**
       * Logout current user
       */
      async logout(): Promise<void> {
        await self.ensureInitialized();
        return self._auth!.logout();
      },

      /**
       * Get current user
       */
      getUser(): NxcodeUser | null {
        return self._auth?.getUser() || null;
      },

      /**
       * Get auth token for API calls
       */
      getToken(): string | null {
        return self._auth?.getToken() || null;
      },

      /**
       * Register auth state change callback
       */
      onAuthStateChange(callback: AuthStateCallback): () => void {
        if (!self._auth) {
          // Store the actual unsubscribe function when SDK initializes
          let actualUnsubscribe: (() => void) | null = null;
          let cancelled = false;

          // Queue callback until initialized
          self.ensureInitialized().then(() => {
            if (!cancelled && self._auth) {
              actualUnsubscribe = self._auth.onAuthStateChange(callback);
            }
          });

          // Return unsubscribe that handles both immediate and deferred cases
          return () => {
            cancelled = true;
            if (actualUnsubscribe) {
              actualUnsubscribe();
            }
          };
        }
        return self._auth.onAuthStateChange(callback);
      },

      /**
       * Check if user is logged in
       */
      isLoggedIn(): boolean {
        return self._auth?.isLoggedIn() || false;
      },
    };
  }

  // ==================== Billing Module ====================

  get billing() {
    const self = this;

    return {
      /**
       * Get user's current balance
       */
      async getBalance(): Promise<number> {
        await self.ensureInitialized();
        return self._billing!.getBalance();
      },

      /**
       * Open top-up page
       */
      topUp(): void {
        self._billing?.topUp();
      },
    };
  }

  // ==================== Payment Module ====================

  get payment() {
    const self = this;

    return {
      /**
       * Process in-app purchase
       */
      async charge(options: ChargeOptions): Promise<ChargeResult> {
        await self.ensureInitialized();
        return self._payment!.charge(options);
      },

      /**
       * Get transaction history
       */
      async getTransactions(limit?: number, offset?: number): Promise<Transaction[]> {
        await self.ensureInitialized();
        return self._payment!.getTransactions(limit, offset);
      },
    };
  }

  // ==================== AI Module ====================

  get ai() {
    const self = this;

    return {
      /**
       * Send a chat message and get a response
       *
       * @example
       * const response = await Nxcode.ai.chat({
       *   messages: [{ role: 'user', content: 'Hello!' }]
       * });
       */
      async chat(options: ChatOptions): Promise<ChatResponse> {
        await self.ensureInitialized();
        return self._ai!.chat(options);
      },

      /**
       * Generate text from a prompt
       *
       * @example
       * const response = await Nxcode.ai.generate({ prompt: 'Write a haiku' });
       */
      async generate(options: GenerateOptions): Promise<GenerateResponse> {
        await self.ensureInitialized();
        return self._ai!.generate(options);
      },

      /**
       * Stream a chat response in real-time
       *
       * @example
       * await Nxcode.ai.chatStream({
       *   messages: [{ role: 'user', content: 'Tell me a story' }],
       *   onChunk: (chunk) => {
       *     document.body.innerText += chunk.content;
       *     if (chunk.done) console.log('Done!');
       *   }
       * });
       */
      async chatStream(options: ChatOptions & { onChunk: StreamCallback }): Promise<void> {
        await self.ensureInitialized();
        return self._ai!.chatStream(options);
      },

      /**
       * Stream text generation from a prompt
       *
       * @example
       * await Nxcode.ai.generateStream({
       *   prompt: 'Write a poem',
       *   onChunk: (chunk) => console.log(chunk.content)
       * });
       */
      async generateStream(options: GenerateOptions & { onChunk: StreamCallback }): Promise<void> {
        await self.ensureInitialized();
        return self._ai!.generateStream(options);
      },

      /**
       * Create an AI agent with tool calling capabilities
       *
       * @example
       * const agent = Nxcode.ai.createAgent({
       *   instructions: 'You are a helpful assistant that can search and send emails.',
       *   tools: [
       *     {
       *       name: 'search_emails',
       *       description: 'Search user emails',
       *       parameters: { query: 'string' },
       *       endpoint: '/api/emails/search'
       *     },
       *     {
       *       name: 'send_email',
       *       description: 'Send an email',
       *       parameters: { to: 'string', subject: 'string', body: 'string' },
       *       endpoint: '/api/emails/send'
       *     }
       *   ]
       * });
       *
       * const result = await agent.run('Find emails from John and reply to him');
       * console.log(result.output);
       */
      createAgent(options: AgentOptions): Agent {
        if (!self.config) {
          throw new Error('Nxcode SDK not configured. Call Nxcode.configure(appId) first.');
        }
        return new Agent(
          options,
          self.apiEndpoint,
          self.config.appId,
          () => self._auth?.getToken() || null
        );
      },
    };
  }

  // ==================== Utility Methods ====================

  /**
   * Get current configuration
   */
  getConfig(): NxcodeConfig | null {
    return this.config;
  }

  /**
   * Check if SDK is ready
   */
  isReady(): boolean {
    return this.config !== null && this._auth !== null;
  }

  /**
   * Wait for SDK to be ready
   */
  async ready(): Promise<void> {
    await this.ensureInitialized();
  }
}

// Create singleton instance
const Nxcode = new NxcodeSDK();

// Export for UMD (browser global)
if (typeof window !== 'undefined') {
  (window as unknown as { Nxcode: typeof Nxcode }).Nxcode = Nxcode;
}

// Export for ESM
export default Nxcode;
export { Nxcode };
export type {
  NxcodeUser,
  NxcodeConfig,
  ChargeOptions,
  ChargeResult,
  Transaction,
  AuthStateCallback,
  ChatOptions,
  ChatResponse,
  ChatMessage,
  ContentPart,
  TextPart,
  ImagePart,
  ImageUrlPart,
  GenerateOptions,
  GenerateResponse,
  StreamChunk,
  StreamCallback,
  SimpleSchema,
  AgentTool,
  AgentOptions,
  AgentRunCallbacks,
  AgentResult,
};
export { Agent };
