/**
 * Nxcode SDK - AI Module
 *
 * Provides access to AI capabilities through the Nxcode AI Gateway.
 * All AI calls require user authentication and are billed to the user's balance.
 */

// ==================== Simplified Schema Types ====================

/**
 * Simplified schema type for structured output.
 *
 * Use simple TypeScript-style notation:
 * - Primitives: 'string', 'number', 'boolean'
 * - Arrays: ['string'], ['number'], [{ nested: 'object' }]
 * - Objects: { key: 'type', nested: { ... } }
 *
 * @example
 * // Simple object
 * { name: 'string', age: 'number', active: 'boolean' }
 *
 * // With arrays
 * { tags: ['string'], scores: ['number'] }
 *
 * // Nested objects
 * { user: { name: 'string', profile: { bio: 'string' } } }
 */
export type SimpleSchema =
  | 'string'
  | 'number'
  | 'boolean'
  | SimpleSchema[]
  | { [key: string]: SimpleSchema };

/**
 * JSON Schema type (Gemini API format)
 */
interface JsonSchema {
  type: 'STRING' | 'NUMBER' | 'INTEGER' | 'BOOLEAN' | 'ARRAY' | 'OBJECT';
  items?: JsonSchema;
  properties?: { [key: string]: JsonSchema };
  required?: string[];
}

/**
 * Convert simplified schema to JSON Schema (Gemini format)
 */
function toJsonSchema(schema: SimpleSchema): JsonSchema {
  // Primitive types
  if (schema === 'string') {
    return { type: 'STRING' };
  }
  if (schema === 'number') {
    return { type: 'NUMBER' };
  }
  if (schema === 'boolean') {
    return { type: 'BOOLEAN' };
  }

  // Array type
  if (Array.isArray(schema)) {
    if (schema.length !== 1) {
      throw new Error('Array schema must have exactly one element type');
    }
    return {
      type: 'ARRAY',
      items: toJsonSchema(schema[0]),
    };
  }

  // Object type
  if (typeof schema === 'object' && schema !== null) {
    const properties: { [key: string]: JsonSchema } = {};
    const required: string[] = [];

    for (const [key, value] of Object.entries(schema)) {
      properties[key] = toJsonSchema(value);
      required.push(key); // All fields required by default
    }

    return {
      type: 'OBJECT',
      properties,
      required,
    };
  }

  throw new Error(`Invalid schema type: ${schema}`);
}

// ==================== Content Part Types ====================

/**
 * Content part for multimodal messages
 */
export interface TextPart {
  type: 'text';
  text: string;
}

export interface ImagePart {
  type: 'image';
  /** Base64 encoded image data */
  data: string;
  /** MIME type (e.g., 'image/png', 'image/jpeg') */
  mimeType: string;
}

export interface ImageUrlPart {
  type: 'image_url';
  /** URL of the image */
  url: string;
}

export type ContentPart = TextPart | ImagePart | ImageUrlPart;

export interface ChatMessage {
  role: 'user' | 'assistant' | 'system';
  /** Text content or array of content parts for multimodal */
  content: string | ContentPart[];
}

export interface ChatOptions {
  messages: ChatMessage[];
  model?: string;
  /** Schema for structured output. AI will return JSON matching this schema. */
  responseSchema?: SimpleSchema;
}

export interface ChatResponse {
  content: string;
  usage?: {
    inputTokens: number;
    outputTokens: number;
  };
}

export interface GenerateOptions {
  prompt: string;
  model?: string;
  /** Schema for structured output. AI will return JSON matching this schema. */
  responseSchema?: SimpleSchema;
}

export interface GenerateResponse {
  text: string;
  usage?: {
    inputTokens: number;
    outputTokens: number;
  };
}

export interface StreamChunk {
  content: string;
  done: boolean;
  usage?: {
    inputTokens: number;
    outputTokens: number;
  };
}

export type StreamCallback = (chunk: StreamChunk) => void;

export class NxcodeAI {
  private apiEndpoint: string;
  private appId: string;
  private getToken: () => string | null;

  constructor(
    apiEndpoint: string,
    appId: string,
    getToken: () => string | null
  ) {
    this.apiEndpoint = apiEndpoint;
    this.appId = appId;
    this.getToken = getToken;
  }

  /**
   * Send a chat message and get a response.
   *
   * @example
   * const response = await Nxcode.ai.chat({
   *   messages: [
   *     { role: 'user', content: 'Hello!' }
   *   ]
   * });
   * console.log(response.content);
   */
  async chat(options: ChatOptions): Promise<ChatResponse> {
    const token = this.getToken();
    // Allow anonymous requests for dev preview and apps with anonymous AI enabled
    const headers = token ? this.getHeaders(token) : this.getAnonymousHeaders();

    const model = options.model || 'fast';

    // Build Gemini API request
    const geminiRequest: Record<string, unknown> = {
      contents: this.convertMessagesToGemini(options.messages),
    };

    // Add structured output config if schema provided
    if (options.responseSchema) {
      geminiRequest.generationConfig = {
        responseMimeType: 'application/json',
        responseSchema: toJsonSchema(options.responseSchema),
      };
    }

    const response = await fetch(
      `${this.apiEndpoint}/api/ai-gateway/v1beta/models/${model}:generateContent`,
      {
        method: 'POST',
        headers,
        body: JSON.stringify(geminiRequest),
      }
    );

    if (!response.ok) {
      await this.handleError(response);
    }

    const data = await response.json();
    return this.parseGeminiResponse(data);
  }

  /**
   * Generate text from a prompt.
   *
   * @example
   * const response = await Nxcode.ai.generate({
   *   prompt: 'Write a haiku about coding'
   * });
   * console.log(response.text);
   */
  async generate(options: GenerateOptions): Promise<GenerateResponse> {
    const result = await this.chat({
      messages: [{ role: 'user', content: options.prompt }],
      model: options.model,
      responseSchema: options.responseSchema,
    });

    return {
      text: result.content,
      usage: result.usage,
    };
  }

  /**
   * Stream a chat response in real-time.
   *
   * @example
   * await Nxcode.ai.chatStream({
   *   messages: [{ role: 'user', content: 'Tell me a story' }],
   *   onChunk: (chunk) => {
   *     process.stdout.write(chunk.content);
   *     if (chunk.done) console.log('\n--- Done ---');
   *   }
   * });
   */
  async chatStream(
    options: ChatOptions & { onChunk: StreamCallback }
  ): Promise<void> {
    const token = this.getToken();
    // Allow anonymous streaming if app permits
    const headers = token ? this.getHeaders(token) : this.getAnonymousHeaders();

    const model = options.model || 'fast';

    const geminiRequest = {
      contents: this.convertMessagesToGemini(options.messages),
    };

    const response = await fetch(
      `${this.apiEndpoint}/api/ai-gateway/v1beta/models/${model}:streamGenerateContent?alt=sse`,
      {
        method: 'POST',
        headers,
        body: JSON.stringify(geminiRequest),
      }
    );

    if (!response.ok) {
      await this.handleError(response);
    }

    const reader = response.body?.getReader();
    if (!reader) {
      throw new Error('Streaming not supported');
    }

    const decoder = new TextDecoder();
    let buffer = '';

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            const jsonStr = line.slice(6).trim();
            if (jsonStr === '[DONE]') {
              options.onChunk({ content: '', done: true });
              return;
            }

            try {
              const data = JSON.parse(jsonStr);
              const chunk = this.parseStreamChunk(data);
              options.onChunk(chunk);
            } catch {
              // Skip invalid JSON
            }
          }
        }
      }

      // Process remaining buffer
      if (buffer.startsWith('data: ')) {
        const jsonStr = buffer.slice(6).trim();
        if (jsonStr && jsonStr !== '[DONE]') {
          try {
            const data = JSON.parse(jsonStr);
            const chunk = this.parseStreamChunk(data);
            options.onChunk(chunk);
          } catch {
            // Skip invalid JSON
          }
        }
      }

      options.onChunk({ content: '', done: true });
    } finally {
      reader.releaseLock();
    }
  }

  /**
   * Stream text generation from a prompt.
   *
   * @example
   * await Nxcode.ai.generateStream({
   *   prompt: 'Write a poem',
   *   onChunk: (chunk) => console.log(chunk.content)
   * });
   */
  async generateStream(
    options: GenerateOptions & { onChunk: StreamCallback }
  ): Promise<void> {
    return this.chatStream({
      messages: [{ role: 'user', content: options.prompt }],
      model: options.model,
      onChunk: options.onChunk,
    });
  }

  // ==================== Private Methods ====================

  private getHeaders(token: string): HeadersInit {
    return {
      'Content-Type': 'application/json',
      'X-App-Id': this.appId,
      Authorization: `Bearer ${token}`,
    };
  }

  private getAnonymousHeaders(): HeadersInit {
    return {
      'Content-Type': 'application/json',
      'X-App-Id': this.appId,
    };
  }

  private convertMessagesToGemini(
    messages: ChatMessage[]
  ): Array<{ role: string; parts: Array<Record<string, unknown>> }> {
    return messages.map((msg) => ({
      role: msg.role === 'assistant' ? 'model' : 'user',
      parts: this.convertContentToParts(msg.content),
    }));
  }

  private convertContentToParts(
    content: string | ContentPart[]
  ): Array<Record<string, unknown>> {
    // Simple text content
    if (typeof content === 'string') {
      return [{ text: content }];
    }

    // Multimodal content
    return content.map((part) => {
      switch (part.type) {
        case 'text':
          return { text: part.text };

        case 'image':
          // Gemini format: inlineData with base64
          return {
            inlineData: {
              mimeType: part.mimeType,
              data: part.data,
            },
          };

        case 'image_url':
          // Gemini format: fileData with URL
          return {
            fileData: {
              fileUri: part.url,
            },
          };

        default:
          return { text: '' };
      }
    });
  }

  private parseGeminiResponse(data: Record<string, unknown>): ChatResponse {
    const candidates = data.candidates as Array<{
      content?: { parts?: Array<{ text?: string }> };
    }>;
    const content =
      candidates?.[0]?.content?.parts?.[0]?.text || '';

    const usageMetadata = data.usageMetadata as {
      promptTokenCount?: number;
      candidatesTokenCount?: number;
    };

    return {
      content,
      usage: usageMetadata
        ? {
            inputTokens: usageMetadata.promptTokenCount || 0,
            outputTokens: usageMetadata.candidatesTokenCount || 0,
          }
        : undefined,
    };
  }

  private parseStreamChunk(data: Record<string, unknown>): StreamChunk {
    const candidates = data.candidates as Array<{
      content?: { parts?: Array<{ text?: string }> };
      finishReason?: string;
    }>;

    const content = candidates?.[0]?.content?.parts?.[0]?.text || '';
    const finishReason = candidates?.[0]?.finishReason;
    const done = finishReason === 'STOP' || finishReason === 'END_TURN';

    const usageMetadata = data.usageMetadata as {
      promptTokenCount?: number;
      candidatesTokenCount?: number;
    };

    return {
      content,
      done,
      usage: usageMetadata
        ? {
            inputTokens: usageMetadata.promptTokenCount || 0,
            outputTokens: usageMetadata.candidatesTokenCount || 0,
          }
        : undefined,
    };
  }

  private async handleError(response: Response): Promise<never> {
    let message = 'AI request failed';
    try {
      const data = await response.json();
      message = data.detail || data.message || message;
    } catch {
      // Ignore parse errors, use default message based on status
      if (response.status === 401) {
        message = 'Session expired. Please login again.';
      } else if (response.status === 402) {
        message = 'Insufficient balance. Please top up to continue.';
      }
    }
    throw new Error(message);
  }
}
